// Merge mega compounds into main database
function mergeMegaCompounds() {
    for (const [key, value] of Object.entries(CompoundsDBMega)) {
        if (!CompoundsDB[key]) {
            CompoundsDB[key] = value;
        }
    }
}

if (typeof CompoundsDB !== 'undefined') mergeMegaCompounds();
